import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { ApiService } from './api.service';
import {
  QuizDetailDto, CreateQuizDto, UpdateQuizDto,
  QuizAttemptDto, SubmitQuizDto, QuizAttemptResultDto, GradeShortAnswerDto,
  QuizSummaryDto, CreateQuestionDto, QuestionDto
} from '../models/quiz.models';

@Injectable({ providedIn: 'root' })
export class QuizService {
  constructor(private api: ApiService) {}

  getById(id: number): Observable<QuizDetailDto> {
    return this.api.get<QuizDetailDto>(`quizzes/${id}`);
  }

  create(dto: CreateQuizDto): Observable<QuizDetailDto> {
    return this.api.post<QuizDetailDto>('quizzes', dto);
  }

  update(id: number, dto: UpdateQuizDto): Observable<QuizDetailDto> {
    return this.api.put<QuizDetailDto>(`quizzes/${id}`, dto);
  }

  delete(id: number): Observable<void> {
    return this.api.delete(`quizzes/${id}`);
  }

  addQuestion(quizId: number, dto: CreateQuestionDto): Observable<QuestionDto> {
    return this.api.post<QuestionDto>(`quizzes/${quizId}/questions`, dto);
  }

  updateQuestion(quizId: number, questionId: number, dto: CreateQuestionDto): Observable<QuestionDto> {
    return this.api.put<QuestionDto>(`quizzes/${quizId}/questions/${questionId}`, dto);
  }

  deleteQuestion(quizId: number, questionId: number): Observable<void> {
    return this.api.delete(`quizzes/${quizId}/questions/${questionId}`);
  }

  startAttempt(quizId: number): Observable<QuizAttemptDto> {
    return this.api.post<QuizAttemptDto>(`quizzes/${quizId}/start`, {});
  }

  submitAttempt(attemptId: number, dto: SubmitQuizDto): Observable<QuizAttemptResultDto> {
    return this.api.post<QuizAttemptResultDto>(`quizzes/attempts/${attemptId}/submit`, dto);
  }

  gradeShortAnswers(attemptId: number, dto: GradeShortAnswerDto): Observable<void> {
    return this.api.post<void>(`quizzes/attempts/${attemptId}/grade-short-answers`, dto);
  }

  getByCourse(courseId: number): Observable<QuizSummaryDto[]> {
    return this.api.getPaged<QuizSummaryDto>('quizzes', { courseId }).pipe(map(r => r.items));
  }
}
